(8, 'WTS Study Abroad Consultant (SMM)', 'wts-study-abroad-consultant-smm', 'Team', 'Admin', '2026-05-01', NULL, 'In Process', 'Social Media', '<p>Research trending topics, important days, festivals &amp; events relevant to the study abroad niche.\r\n<br>Write scripts for reference videos and develop content ideas as per brand tone.<br>&nbsp;Content Calendar Creation Plan and schedule monthly content across all social media platforms\r\n<br>Coordinate with the respective person and do the video shoots\r\nshare raw content with the editing team.<br>&nbsp;Share final content for approval and publish the content<br>&nbsp;Reference Finding for Posts &amp; Carousels and create the text copy</p>', NULL, '2026-05-15 12:53:40', '2026-05-21 05:05:08', '[\"25\"]', '[\"24\"]'),
(9, 'Iron street ( SMM)', 'iron-street-smm', 'Team', 'Admin', '2026-05-01', NULL, 'In Process', 'Social Media', '<ul>\r\n<li>Monthly Planning &amp; Research Research trending topics, important days, festivals &amp; events relevant to the furniture niche.</li>\r\n<li>Content Calendar Creation Plan and schedule monthly content across all social media platforms.</li>\r\n<li>conduct product shoots.</li>\r\n<li>Share raw data of videos content with the editing team.</li>\r\n<li>Share final content for approval and publish the content.</li>\r\n<li>Find references for posts &amp; carousels and create the text copy accordingly.</li>\r\n<li>Share performance, prepare monthly reports.</li></ul>', NULL, '2026-05-15 13:09:56', '2026-05-21 05:04:37', '[\"25\"]', '[\"24\"]'),
(10, 'Yellow Sapphire (SMM)', 'yellow-sapphire-smm', 'Team', 'Admin', '2026-05-01', NULL, 'In Process', 'Social Media', '<p data-pm-slice=\"1 1 []\">Handled and managed the posting for Yellow Sapphire across platforms.</p><p>Take the approval for pointers for creative </p><p>Watched the testimonial reel and prepared pointers from it for further use.</p><p>Reviewed the document and provided the necessary changes and edits to the designer</p><p>Do the creative and reel  posting on social media platforms&nbsp;</p>', NULL, '2026-05-18 08:52:44', '2026-05-21 05:05:30', '[\"25\"]', '[\"24\"]'),
(11, 'Warrgyizmorsch (SMM)', 'warrgyizmorsch-smm', 'Team', 'Admin', '2026-05-01', NULL, 'In Process', 'Social Media', '<p data-pm-slice=\"1 1 []\">Research trending topics, important days, festivals &amp; events relevant to the IT &amp; software industry.</p><p>Write scripts for reference videos and develop content ideas as per brand tone and on specific services </p><p>Coordinate with the respective person and conduct video shoots.</p><p>Share raw content with the editing team.</p><p>Share the final content for approval and publish the content.</p><p>Find references for posts &amp; carousels and create the text copy accordingly.</p><p>Post and schedule monthly content across all social media platforms.</p>', NULL, '2026-05-18 09:00:54', '2026-05-21 05:05:47', '[\"25\"]', '[\"24\"]'),
(12, 'Democracy Asia (SMM)', 'democracy-asia-smm', 'Team', 'Admin', '2026-05-01', NULL, 'In Process', 'Social Media', '<p data-pm-slice=\"1 1 []\">Post articles across Twitter, Medium, Instagram, Facebook, LinkedIn, Threads, Telegram &amp; WhatsApp Community.</p><p>Generate individual cover images for each article\'s first post across platforms.</p><p>Prepare and provide content for short videos on YouTube &amp; TikTok based on the articles.</p><p>Prepare compelling titles and descriptions for each short video accordingly.</p>', NULL, '2026-05-18 09:52:33', '2026-05-21 05:06:08', '[\"25\"]', '[\"24\"]'),
