INSERT INTO `task_follow_ups` (`id`, `daily_task_id`, `project_id`, `work_description`, `reference_name`, `time_taken`, `photo`, `created_at`, `updated_at`) VALUES
(8, 12, NULL, '<div class=\"mb-4\" style=\"border-left: 4px solid #3858f9; padding-left: 20px;\">\r\n                                                            <p class=\"mb-2\" style=\"font-size: 16px; color: #1e293b;\"><strong>• WORKING ON IT</strong> — <b style=\"color: #3858f9;\">4 Hours</b></p>\r\n                                                            <ol class=\"text-muted\" style=\"font-size: 14px; line-height: 1.7;\">\r\n                                                                <li>&nbsp;still testing</li>\r\n                                                            </ol>\r\n                                                          </div><hr style=\"border-top: 2px solid #f1f5f9; margin: 20px 0;\">', 'ANSHUL SUTHAR (KHETA RAM)', '4', NULL, '2026-05-06 07:31:29', '2026-05-06 07:31:29'),
(9, 13, NULL, '<div class=\"mb-4\" style=\"border-left: 4px solid #3858f9; padding-left: 20px;\">\r\n                                                            <p class=\"mb-2\" style=\"font-size: 16px; color: #1e293b;\"><strong>• CREAETD 2 SCRIPTS</strong> — <b style=\"color: #3858f9;\">2 Hours</b></p>\r\n                                                            <ol class=\"text-muted\" style=\"font-size: 14px; line-height: 1.7;\">\r\n                                                                <li>&nbsp;mother day</li><li>&nbsp;father day</li>\r\n                                                            </ol>\r\n                                                          </div><hr style=\"border-top: 2px solid #f1f5f9; margin: 20px 0;\"><br>', 'Nisha Mewara', '4.3', NULL, '2026-05-06 07:50:59', '2026-05-06 07:50:59'),
(10, 22, NULL, '<div class=\"sub-task-item mb-4\" data-time=\"1.5\" style=\"border-left: 4px solid #3858f9; padding-left: 20px;\">\r\n                                                            <p class=\"mb-2\" style=\"font-size: 16px; color: #1e293b;\"><strong>•  FIX THE USER STATUS AND ALL COMMENTS ARE SHOW BEFORE IN WARRGYIZMORCH CRM</strong> — <b style=\"color: #3858f9;\">1h 30m</b><span style=\"color: rgb(100, 116, 139); font-size: 14px;\">&nbsp;</span></p><ol class=\"text-muted\" style=\"font-size: 14px; line-height: 1.7;\"><li data-section-id=\"1t2xlde\" data-start=\"0\" data-end=\"201\">Fixed the user status functionality in the Warrgyizmorsch CRM and ensured that the correct active or inactive status is properly updated and displayed across all modules without any mismatch issues.\r\n</li>\r\n<li data-section-id=\"1y7g7bu\" data-start=\"203\" data-end=\"388\">\r\nImproved the CRM comment management system by showing all previous comments in proper sequence, allowing users to easily track complete lead communication history from the beginning.\r\n</li>\r\n<li data-section-id=\"1r5s9yn\" data-start=\"390\" data-end=\"570\">\r\nResolved the issue where old comments were not loading correctly in the CRM, and now every comment related to the lead is fetched and displayed properly with updated timestamps.\r\n</li>\r\n<li data-section-id=\"uetcls\" data-start=\"572\" data-end=\"747\">\r\nOptimized the lead activity section in Warrgyizmorsch CRM so that user status changes and comment updates are reflected instantly without requiring multiple page refreshes.\r\n</li>\r\n<li data-section-id=\"2ipda\" data-start=\"749\" data-end=\"938\" data-is-last-node=\"\">\r\nPerformed complete testing of the CRM user status and comments module to ensure smooth functionality, better visibility of lead discussions, and accurate data handling across the system.</li>\r\n                                                            </ol>\r\n                                                          </div><hr class=\"sub-task-hr\" style=\"border-top: 2px solid #f1f5f9; margin: 20px 0;\"><div class=\"sub-task-item mb-4\" data-time=\"1.5\" style=\"border-left: 4px solid rgb(56, 88, 249); padding-left: 20px;\"><p class=\"mb-2\" style=\"font-size: 16px; color: rgb(30, 41, 59);\"></p></div>', 'Ranjit Singh Shaktawat', '1.50', NULL, '2026-05-20 11:49:35', '2026-05-20 11:49:35'),
(11, 15, NULL, '<div class=\"sub-task-item mb-4\" data-time=\"6.5\" style=\"border-left: 4px solid #3858f9; padding-left: 20px;\">\r\n                                                            <p class=\"mb-2\" style=\"font-size: 16px; color: #1e293b;\"><strong>• HOME PAGE ADDED ALL SECTION ANIMATION AND AND HERO SECTION UI FIX </strong> — <b style=\"color: #3858f9;\">6h 30m</b></p><ol class=\"text-muted\" style=\"font-size: 14px; line-height: 1.7;\"><li data-section-id=\"1qe9i6x\" data-start=\"0\" data-end=\"208\">Completed the Home Page Hero Section with a fully responsive and modern UI design, including proper content alignment, banner layout, call-to-action buttons, and smooth visual presentation for all devices.\r\n</li>\r\n<li data-section-id=\"5p0pl0\" data-start=\"210\" data-end=\"402\">\r\nDeveloped and finalized the Steps Section on the Home Page by organizing the process flow in a clean and user-friendly structure, making it easier for users to understand each step clearly.\r\n</li>\r\n<li data-section-id=\"4syb73\" data-start=\"404\" data-end=\"616\">\r\nCompleted the “Why Parents Choose Us” section with enhanced UI styling, proper spacing, attractive content presentation, and responsive design improvements to highlight the platform’s key benefits effectively.\r\n</li>\r\n<li data-section-id=\"xh8m2y\" data-start=\"618\" data-end=\"815\">\r\nAdded and designed multiple additional sections on the Home Page with improved layouts, consistent styling, and optimized responsiveness to create a complete and professional website experience.\r\n</li>\r\n<li data-section-id=\"5x88wt\" data-start=\"817\" data-end=\"1050\" data-is-last-node=\"\">\r\nImplemented smooth animations and transition effects across the Hero Section, Steps Section, Why Parents Choose Us section, and other Home Page components to improve user interaction and create a more engaging frontend experience.</li>\r\n                                                            </ol>\r\n                                                          </div><hr class=\"sub-task-hr\" style=\"border-top: 2px solid #f1f5f9; margin: 20px 0;\">', 'Ranjit Singh Shaktawat', '6.50', NULL, '2026-05-20 11:55:51', '2026-05-20 11:55:51'),
(12, 16, NULL, '<div class=\"sub-task-item mb-4\" data-time=\"7\" style=\"border-left: 4px solid #3858f9; padding-left: 20px;\" bis_skin_checked=\"1\">\r\n                                                            <p class=\"mb-2\" style=\"font-size: 16px; color: #1e293b;\"><strong>• CREATE PROJECT STAGES MASTERS</strong> —&nbsp;</p>\r\n                                                          </div><hr class=\"sub-task-hr\" style=\"border-top: 2px solid #f1f5f9; margin: 20px 0;\"><p><span style=\"font-size: 13.44px;\">1.Updated Requisition View screen: machine data now displayed in proper column-wise format for better readability.</span></p><p><span style=\"font-size: 13.44px;\">2.Added clickable project name links across the system to redirect users to the respective project detail page.</span></p><p><span style=\"font-size: 13.44px;\">3.Completed full implementation of Stages and Sub Stages master modules, including database design, migrations,&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;models, controllers, and complete CRUD functionality with relationships for future workflow integration.</span></p>', 'Manish patidar', '7.00', NULL, '2026-05-20 12:30:51', '2026-05-20 12:30:51'),
(13, 21, NULL, '<p data-start=\"90\" data-end=\"102\"><strong data-start=\"90\" data-end=\"102\">SIP CRM:</strong></p>\r\n<ul data-start=\"103\" data-end=\"671\" data-is-last-node=\"\" data-is-only-node=\"\">\r\n<li data-section-id=\"1y6uyrr\" data-start=\"103\" data-end=\"215\">\r\nDesigned and completed UI for <strong data-start=\"135\" data-end=\"156\">three new screens</strong>: <strong data-start=\"158\" data-end=\"212\">Edit Page, Portfolio Holding, and Industry Holding</strong>.\r\n</li>\r\n<li data-section-id=\"1hlj2f7\" data-start=\"216\" data-end=\"309\">\r\nMade the <strong data-start=\"227\" data-end=\"254\">Edit Page fully dynamic</strong> and integrated complete data handling functionality.\r\n</li>\r\n<li data-section-id=\"6qoo51\" data-start=\"310\" data-end=\"392\">\r\nAdded a <strong data-start=\"320\" data-end=\"342\">new card component</strong> for improved data saving and display structure.\r\n</li>\r\n<li data-section-id=\"1kepqib\" data-start=\"393\" data-end=\"467\">\r\nResolved issues related to <strong data-start=\"422\" data-end=\"464\">database changes and data flow updates</strong>.\r\n</li>\r\n<li data-section-id=\"wqr33x\" data-start=\"468\" data-end=\"570\">\r\nTested the complete <strong data-start=\"490\" data-end=\"531\">NFO to Mutual Fund conversion process</strong> and due-date workflow functionality.\r\n</li>\r\n<li data-section-id=\"9rshvm\" data-start=\"571\" data-end=\"671\" data-is-last-node=\"\">\r\nContinued work on making <strong data-start=\"598\" data-end=\"632\">two additional screens dynamic</strong> and integrating related functionality.</li></ul>', 'Nikhil Sharma', '0.00', NULL, '2026-05-20 12:33:59', '2026-05-20 12:33:59'),
(14, 16, NULL, '<span style=\"font-size: 13.44px;\">Added \"Today\" and \"Yesterday\" filter buttons in Leads module .</span>', 'Manish patidar', '0.00', NULL, '2026-05-20 12:35:05', '2026-05-20 12:35:05'),
(15, 18, NULL, '<p data-start=\"23\" data-end=\"47\"><strong data-start=\"23\" data-end=\"47\">Today\'s Task Report:</strong></p>\r\n<ul data-start=\"49\" data-end=\"601\" data-is-last-node=\"\" data-is-only-node=\"\">\r\n<li data-section-id=\"1k3ew38\" data-start=\"49\" data-end=\"166\">\r\nCopied and integrated required models, controllers, routes, migrations, and blade files into the project structure.\r\n</li>\r\n<li data-section-id=\"2r0hry\" data-start=\"167\" data-end=\"292\">\r\nImplemented necessary changes in provider and configuration files to ensure proper application flow and module integration.\r\n</li>\r\n<li data-section-id=\"ki0kdi\" data-start=\"293\" data-end=\"365\">\r\nWorked on configuring and troubleshooting the tenant creation process.\r\n</li>\r\n<li data-section-id=\"806gtf\" data-start=\"366\" data-end=\"503\">\r\nInvestigated and attempted to resolve the issue where a new database should be automatically created during tenant onboarding/creation.\r\n</li>\r\n<li data-section-id=\"8z0vh\" data-start=\"504\" data-end=\"601\" data-is-last-node=\"\">\r\nTested and analyzed the database generation flow to identify integration and automation issues.</li></ul>', 'Jay Sahu', '0.00', NULL, '2026-05-20 12:39:52', '2026-05-20 12:39:52'),
(16, 28, NULL, 'Done Deployment', 'Jay Sahu', '0.00', NULL, '2026-05-20 12:41:57', '2026-05-20 12:41:57'),
