INSERT INTO `task_follow_ups` (`id`, `daily_task_id`, `project_id`, `work_description`, `reference_name`, `time_taken`, `photo`, `created_at`, `updated_at`) VALUES
(129, 196, NULL, '<div class=\"sub-task-item mb-4\" data-time=\"4\" style=\"border-left: 4px solid #3858f9; padding-left: 20px;\">\r\n                                                            <p class=\"mb-2\" style=\"font-size: 16px; color: #1e293b;\"><strong>• TEST ANF FIXED ALL ISUUES(UI AND LOGICAL))</strong> — <b style=\"color: #3858f9;\">4h</b><span style=\"color: rgb(100, 116, 139); font-size: 14px;\">&nbsp;</span><span style=\"background-color: rgb(248, 250, 252); color: rgb(100, 116, 139); font-family: Inter, sans-serif; font-size: 0.875em;\">Fixed data accuracy issues in </span><span data-start=\"170\" data-end=\"184\" style=\"background-color: rgb(248, 250, 252); color: rgb(100, 116, 139); font-family: Inter, sans-serif; font-size: 0.875em; font-weight: 600;\">Categories</span><span style=\"background-color: rgb(248, 250, 252); color: rgb(100, 116, 139); font-family: Inter, sans-serif; font-size: 0.875em;\"> and </span><span data-start=\"189\" data-end=\"206\" style=\"background-color: rgb(248, 250, 252); color: rgb(100, 116, 139); font-family: Inter, sans-serif; font-size: 0.875em; font-weight: 600;\">Subcategories</span><span style=\"background-color: rgb(248, 250, 252); color: rgb(100, 116, 139); font-family: Inter, sans-serif; font-size: 0.875em;\"> pages, including product count and status display.</span></p><ol class=\"text-muted\" style=\"font-size: 14px; line-height: 1.7;\"><li>Improved <span data-start=\"272\" data-end=\"315\" style=\"font-weight: 600;\">pagination, search, and filter handling</span> for Customers, Suppliers, Transporters, and listing pages.<div class=\"text-muted small mb-2\" style=\"font-family: Inter, sans-serif; background-color: rgb(248, 250, 252);\"></div></li><li data-section-id=\"dyr6gi\" data-start=\"377\" data-end=\"500\" style=\"margin-bottom: 0.6rem !important;\">Fixed UI and action issues in <span data-start=\"410\" data-end=\"491\" style=\"font-weight: 600;\">Suppliers, Transporters, Business Profile, Sale Details