(181, 274, 33, '\n            <div class=\"mb-4\" style=\"padding-left: 8px; font-family: system-ui, sans-serif;\">\n                <p class=\"mb-3\" style=\"font-size: 16px; color: #1e293b; margin-bottom: 10px; font-weight: 700;\">\n                    <span style=\"color: #1e293b;\">&bull; Saas ERP</span>\n                    <span style=\"color: #3858f9; font-weight: 700;\"> - 6h 30m</span>\n                </p>\n                <ol class=\"text-muted\" style=\"font-size: 14px; line-height: 1.9; padding-left: 24px; color: #64748b; margin: 0;\">\n                    <li style=\"margin-bottom: 6px;\">Enhanced the sidebar UI for better design and user experience.</li><li style=\"margin-bottom: 6px;\">Updated and changed the application logo.</li><li style=\"margin-bottom: 6px;\">Worked on multiple bugs in the HRMS module where several pages and functionalities were not working properly.</li><li style=\"margin-bottom: 6px;\">Fixed the issue in the HRMS module where the employee list was not appearing in the Create Project section.</li><li style=\"margin-bottom: 6px;\">Resolved issues related to project creation functionality in the HRMS module.</li><li style=\"margin-bottom: 6px;\">Worked on User Rights management by creating a seeder for all current menus.</li><li style=\"margin-bottom: 6px;\">Fixed dynamic menu visibility based on user rights and permissions.</li><li style=\"margin-bottom: 6px;\">Resolved several issues in the Inventory Management module.</li>\n                </ol>\n            </div>', 'Jay Sahu', '6.5', NULL, '2026-05-27 12:18:49', '2026-05-27 12:18:49'),
