(188, 277, 34, '\n            <div class=\"mb-4\" style=\"padding-left: 8px; font-family: system-ui, sans-serif;\">\n                <p class=\"mb-3\" style=\"font-size: 16px; color: #1e293b; margin-bottom: 10px; font-weight: 700;\">\n                    <span style=\"color: #1e293b;\">&bull; HRMS WARRGYIZMORSCH DEVELOPMET</span>\n                    <span style=\"color: #3858f9; font-weight: 700;\"> - 8h</span>\n                </p>\n                <ol class=\"text-muted\" style=\"font-size: 14px; line-height: 1.9; padding-left: 24px; color: #64748b; margin: 0;\">\n                    <li style=\"margin-bottom: 6px;\">Implemented a new Broadcast Module to send announcements/messages across the system.</li><li style=\"margin-bottom: 6px;\">Added functionality to display broadcast messages directly on the employee dashboard.</li><li style=\"margin-bottom: 6px;\">Implemented department-wise message broadcasting for targeted communication.</li><li style=\"margin-bottom: 6px;\">Added message view tracking, allowing employees to mark broadcasts as viewed.</li><li style=\"margin-bottom: 6px;\">Stored employee view logs with employee name and timestamp for admin monitoring.</li><li style=\"margin-bottom: 6px;\">Integrated the Job Vacancy Module with the Job Requirement Module and implemented role-wise interview count tracking with redirection to view scheduled interviews for the selected role.</li><li style=\"margin-bottom: 6px;\">Added clickable interview count functionality to redirect and display scheduled interviews for the selected role.</li><li style=\"margin-bottom: 6px;\">Added a Members column in the Project Module with functionality to update and manage assigned project team members.</li>\n                </ol>\n            </div>', 'Mohammad Kaif', '8', NULL, '2026-05-27 12:35:10', '2026-05-27 12:35:10'),
